const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=Number(input[idx++]);
let res=[];
for(let t=0;t<T;++t){
  const N=Number(input[idx++]);
  const S=input[idx++];
  let ans=0;
  for(let i=1;i<N;++i){if(S[i]===S[i-1])++ans;}
  res.push(String(ans));
}
console.log(res.join('\n'));
